import{_ as t,o as e,c as s,ae as n}from"./chunks/framework.Cz5DOqVF.js";const u=JSON.parse('{"title":"GDPVal Benchmark","description":"","frontmatter":{},"headers":[],"relativePath":"benchmark.md","filePath":"benchmark.md"}'),r={name:"benchmark.md"};function o(l,a,i,d,h,c){return e(),s("div",null,[...a[0]||(a[0]=[n(`<h1 id="gdpval-benchmark" tabindex="-1">GDPVal Benchmark <a class="header-anchor" href="#gdpval-benchmark" aria-label="Permalink to &quot;GDPVal Benchmark&quot;">​</a></h1><blockquote><p>Real-world evaluation on 50 professional tasks across 6 industries.</p></blockquote><h2 id="_1-benchmark-overview" tabindex="-1">1. Benchmark Overview <a class="header-anchor" href="#_1-benchmark-overview" aria-label="Permalink to &quot;1. Benchmark Overview&quot;">​</a></h2><p><strong>GDPVal</strong> = <strong>G</strong>DP <strong>Val</strong>idation</p><p>A benchmark evaluating AI agents on real economic tasks — the kind of work that generates actual GDP.</p><h3 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h3><ul><li>50 real-world professional tasks</li><li>6 industries: Documents, Compliance, Media, Engineering, Spreadsheets, Strategy</li><li>44 occupations from the GDPVal dataset</li></ul><h3 id="methodology" tabindex="-1">Methodology <a class="header-anchor" href="#methodology" aria-label="Permalink to &quot;Methodology&quot;">​</a></h3><ul><li><strong>Phase 1 (Cold Start)</strong>: Run all 50 tasks sequentially, skills accumulate</li><li><strong>Phase 2 (Warm Rerun)</strong>: Re-execute with evolved skill database from Phase 1</li></ul><h2 id="_2-key-results" tabindex="-1">2. Key Results <a class="header-anchor" href="#_2-key-results" aria-label="Permalink to &quot;2. Key Results&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><strong>Income Δ</strong></td><td>4.2×</td><td>vs ClawWork baseline</td></tr><tr><td><strong>Value Capture</strong></td><td>72.8%</td><td>$11,484 earned of $15,764 possible</td></tr><tr><td><strong>Quality</strong></td><td>70.8%</td><td>+30pp above best ClawWork (40.8%)</td></tr><tr><td><strong>Token Reduction</strong></td><td>45.9%</td><td>Phase 2 vs Phase 1</td></tr></tbody></table><h2 id="_3-results-by-category" tabindex="-1">3. Results by Category <a class="header-anchor" href="#_3-results-by-category" aria-label="Permalink to &quot;3. Results by Category&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Income Δ</th><th>Token Δ</th><th>Key Insight</th></tr></thead><tbody><tr><td><strong>📝 Documents</strong></td><td>+3.3pp</td><td>−56%</td><td>13-version evolution of doc pipelines</td></tr><tr><td><strong>📋 Compliance</strong></td><td>+18.5pp</td><td>−51%</td><td>PDF skill chain evolves once, reuses everywhere</td></tr><tr><td><strong>🎬 Media</strong></td><td>+5.8pp</td><td>−46%</td><td>ffmpeg flags and codec fallbacks cached</td></tr><tr><td><strong>🛠️ Engineering</strong></td><td>+8.7pp</td><td>−43%</td><td>Coordination skills transfer universally</td></tr><tr><td><strong>📊 Spreadsheets</strong></td><td>+7.3pp</td><td>−37%</td><td>Formula/validation patterns identical across domains</td></tr><tr><td><strong>📈 Strategy</strong></td><td>+1.0pp</td><td>−32%</td><td>Already highest quality; savings from reuse</td></tr></tbody></table><h2 id="_4-what-was-evolved-165-skills" tabindex="-1">4. What Was Evolved? (165 Skills) <a class="header-anchor" href="#_4-what-was-evolved-165-skills" aria-label="Permalink to &quot;4. What Was Evolved? (165 Skills)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Purpose</th><th>Count</th><th>Example</th></tr></thead><tbody><tr><td>File Format I/O</td><td>44</td><td>PDF extraction fallbacks, DOCX parsing</td></tr><tr><td>Execution Recovery</td><td>29</td><td>Layered fallback: sandbox → shell → heredoc</td></tr><tr><td>Document Generation</td><td>26</td><td>document-gen-fallback (13 versions!)</td></tr><tr><td>Quality Assurance</td><td>23</td><td>Post-write verification</td></tr><tr><td>Task Orchestration</td><td>17</td><td>Multi-file tracking, ZIP packaging</td></tr><tr><td>Domain Workflow</td><td>13</td><td>SOAP notes, audio production</td></tr><tr><td>Web &amp; Research</td><td>11</td><td>SSL/proxy debugging</td></tr></tbody></table><h2 id="_5-why-evolution-works" tabindex="-1">5. Why Evolution Works <a class="header-anchor" href="#_5-why-evolution-works" aria-label="Permalink to &quot;5. Why Evolution Works&quot;">​</a></h2><h3 id="the-breakthrough-insight" tabindex="-1">The Breakthrough Insight <a class="header-anchor" href="#the-breakthrough-insight" aria-label="Permalink to &quot;The Breakthrough Insight&quot;">​</a></h3><p>Most skills focus on <strong>tool reliability and error recovery</strong>, not task-specific knowledge.</p><p>Agents don&#39;t need to learn &quot;how to do taxes&quot; — they need to learn:</p><ul><li>How to reliably read PDF files</li><li>How to recover from sandbox failures</li><li>How to verify output quality</li></ul><h3 id="skill-taxonomy" tabindex="-1">Skill Taxonomy <a class="header-anchor" href="#skill-taxonomy" aria-label="Permalink to &quot;Skill Taxonomy&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Skills Learned</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 44% Tool Reliability</span></span>
<span class="line"><span>    │   └── (PDF/DOCX/Excel I/O, fallbacks)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 18% Error Recovery</span></span>
<span class="line"><span>    │   └── (sandbox → shell → heredoc)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 16% Quality Gates</span></span>
<span class="line"><span>    │   └── (verify before deliver)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 22% Task Execution</span></span>
<span class="line"><span>        └── (orchestration, domain workflows)</span></span></code></pre></div><h2 id="_6-economic-value" tabindex="-1">6. Economic Value <a class="header-anchor" href="#_6-economic-value" aria-label="Permalink to &quot;6. Economic Value&quot;">​</a></h2><h3 id="value-capture-formula" tabindex="-1">Value Capture Formula <a class="header-anchor" href="#value-capture-formula" aria-label="Permalink to &quot;Value Capture Formula&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Income Capture = actual_earnings / maximum_task_value</span></span></code></pre></div><h3 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h3><ul><li><strong>$11,484</strong> earned out of <strong>$15,764</strong> task value</li><li><strong>72.8%</strong> value capture rate</li><li>Outperforms all baseline agents</li></ul><h2 id="_7-token-efficiency" tabindex="-1">7. Token Efficiency <a class="header-anchor" href="#_7-token-efficiency" aria-label="Permalink to &quot;7. Token Efficiency&quot;">​</a></h2><h3 id="phase-1-vs-phase-2" tabindex="-1">Phase 1 vs Phase 2 <a class="header-anchor" href="#phase-1-vs-phase-2" aria-label="Permalink to &quot;Phase 1 vs Phase 2&quot;">​</a></h3><ul><li><strong>46% fewer tokens</strong> in Phase 2</li><li><strong>Better results</strong> (higher income)</li><li><strong>4.2× income improvement</strong></li></ul><p>This is the token efficiency flywheel:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>More Skills → Better Selection → Less Reasoning → Fewer Tokens</span></span></code></pre></div><h2 id="_8-fair-comparison" tabindex="-1">8. Fair Comparison <a class="header-anchor" href="#_8-fair-comparison" aria-label="Permalink to &quot;8. Fair Comparison&quot;">​</a></h2><p>OpenSpace uses <strong>Qwen 3.5-Plus</strong> as backbone LLM — identical to ClawWork baseline.</p><p>This ensures performance differences stem purely from <strong>skill evolution</strong>, not model capabilities.</p><h2 id="_9-reproduce-results" tabindex="-1">9. Reproduce Results <a class="header-anchor" href="#_9-reproduce-results" aria-label="Permalink to &quot;9. Reproduce Results&quot;">​</a></h2><p>Full experiment code, analysis tools, and results available at:</p><ul><li><a href="https://github.com/HKUDS/OpenSpace/tree/main/gdpval_bench" target="_blank" rel="noreferrer"><code>gdpval_bench/README.md</code></a></li></ul><p>Includes:</p><ul><li>Experiment runner</li><li>Data analysis scripts</li><li>Result visualizations</li><li>Skill lineage database</li></ul>`,40)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
